<?php
namespace App\Http\Controllers; use App\Models\{KnowledgeMachine,KnowledgeServiceCode}; use App\Support\Audit; use Illuminate\Http\{JsonResponse,Request,Response};
class KnowledgeServiceCodeController extends Controller { public function index(KnowledgeMachine $knowledgeMachine):JsonResponse{return response()->json($knowledgeMachine->serviceCodes()->get()->map(fn($c)=>['id'=>$c->id,'function_name'=>$c->function_name,'description'=>$c->description,'has_service_code'=>filled($c->service_code)]));} public function store(Request $r,KnowledgeMachine $knowledgeMachine):JsonResponse{$this->admin($r);$d=$this->valid($r);$d+=['knowledge_machine_id'=>$knowledgeMachine->id,'created_by'=>$r->user()->id,'updated_by'=>$r->user()->id];$c=KnowledgeServiceCode::create($d);Audit::record($r,'service_code.created',$c);return response()->json(['id'=>$c->id,'function_name'=>$c->function_name,'description'=>$c->description,'has_service_code'=>true],201);} public function update(Request $r,KnowledgeServiceCode $knowledgeServiceCode):JsonResponse{$this->admin($r);$d=$this->valid($r,true);$d['updated_by']=$r->user()->id;$knowledgeServiceCode->update($d);Audit::record($r,'service_code.updated',$knowledgeServiceCode);return response()->json(['id'=>$knowledgeServiceCode->id,'function_name'=>$knowledgeServiceCode->function_name,'description'=>$knowledgeServiceCode->description,'has_service_code'=>filled($knowledgeServiceCode->service_code)]);} public function destroy(Request $r,KnowledgeServiceCode $knowledgeServiceCode):Response{$this->admin($r);$knowledgeServiceCode->delete();return response()->noContent();} public function reveal(Request $r,KnowledgeServiceCode $knowledgeServiceCode):JsonResponse{abort_unless(in_array($r->user()->role,['admin','technician']),403);Audit::record($r,'service_code.revealed',$knowledgeServiceCode);return response()->json(['service_code'=>$knowledgeServiceCode->service_code]);} private function admin(Request $r):void{abort_unless($r->user()->role==='admin',403);} private function valid(Request $r,bool $p=false):array{$x=$p?'sometimes|required':'required';return $r->validate(['function_name'=>[$x,'string','max:255'],'description'=>['sometimes','nullable','string'],'service_code'=>[$x,'string','max:2000']]);}}
